import{_ as t,o as a,c as o,ag as s}from"./chunks/framework.BOaOek6C.js";const m=JSON.parse('{"title":"Monorepo structure","description":"","frontmatter":{},"headers":[],"relativePath":"overview/monorepo-structure.md","filePath":"overview/monorepo-structure.md"}'),n={name:"overview/monorepo-structure.md"};function r(d,e,i,p,l,c){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="monorepo-structure" tabindex="-1">Monorepo structure <a class="header-anchor" href="#monorepo-structure" aria-label="Permalink to &quot;Monorepo structure&quot;">​</a></h1><p>This repository is a <strong>pnpm workspace</strong> for MdEditor: one checkout, several packages, shared tooling at the root.</p><h2 id="packages-pnpm-filter-names" tabindex="-1">Packages (pnpm <code>--filter</code> names) <a class="header-anchor" href="#packages-pnpm-filter-names" aria-label="Permalink to &quot;Packages (pnpm \`--filter\` names)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Package</th><th>Path</th><th>Role</th></tr></thead><tbody><tr><td><strong>mdeditor</strong></td><td><code>ui/mdeditor</code></td><td>Main Ember <strong>application</strong>: routes, pages, and how product screens are composed.</td></tr><tr><td><strong>core</strong></td><td><code>addons/core</code></td><td><strong>Reusable logic</strong> addon: services, helpers, and primitives that are not focused on visual UI.</td></tr><tr><td><strong>md</strong></td><td><code>addons/md</code></td><td><strong>Shared UI</strong> addon: layout shell, navigation chrome, styles, design tokens.</td></tr><tr><td><strong>mdeditor-handbook</strong></td><td><code>docs/handbook</code></td><td>This <strong>documentation</strong> site (VitePress → static HTML).</td></tr></tbody></table><p>Other Ember apps or addons can be added under <code>ui/*</code> or <code>addons/*</code> and registered in <code>pnpm-workspace.yaml</code>.</p><h2 id="how-the-pieces-fit-together" tabindex="-1">How the pieces fit together <a class="header-anchor" href="#how-the-pieces-fit-together" aria-label="Permalink to &quot;How the pieces fit together&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  mdeditor (app)                                         │</span></span>
<span class="line"><span>│  routes, controllers, templates, app-specific UI        │</span></span>
<span class="line"><span>└───────────────┬─────────────────────────────────────────┘</span></span>
<span class="line"><span>                │ depends on</span></span>
<span class="line"><span>        ┌───────┴───────┐</span></span>
<span class="line"><span>        ▼               ▼</span></span>
<span class="line"><span>┌──────────────┐  ┌──────────────┐</span></span>
<span class="line"><span>│  md (UI)     │  │  core        │</span></span>
<span class="line"><span>│  shell, nav  │  │  i18n, etc.  │</span></span>
<span class="line"><span>│  styles      │  │              │</span></span>
<span class="line"><span>└──────────────┘  └──────────────┘</span></span></code></pre></div><ul><li><strong>Business flows and screens</strong> usually start in <strong>mdeditor</strong>.</li><li><strong>Look-and-feel and shared chrome</strong> come from <strong>md</strong>.</li><li><strong>Shared non-UI behavior</strong> tends to live in <strong>core</strong>.</li></ul><h2 id="root-level-scripts" tabindex="-1">Root-level scripts <a class="header-anchor" href="#root-level-scripts" aria-label="Permalink to &quot;Root-level scripts&quot;">​</a></h2><p>From the repository root, common entry points include:</p><table tabindex="0"><thead><tr><th>Goal</th><th>Command</th></tr></thead><tbody><tr><td>Install all packages</td><td><code>pnpm install</code></td></tr><tr><td>Build the MdEditor UI</td><td><code>pnpm build</code> or <code>pnpm build:ui:mdeditor</code></td></tr><tr><td>Lint everything</td><td><code>pnpm lint</code></td></tr><tr><td>Test everything</td><td><code>pnpm test</code></td></tr><tr><td>Accessibility tests (mdeditor)</td><td><code>pnpm test-a11y</code></td></tr></tbody></table><p>Filter to one package with <code>pnpm run --filter &lt;name&gt; &lt;script&gt;</code> (see <a href="./developer-setup.html">Developer setup</a>).</p><h2 id="related-reading" tabindex="-1">Related reading <a class="header-anchor" href="#related-reading" aria-label="Permalink to &quot;Related reading&quot;">​</a></h2><ul><li><a href="./../apps/mdeditor.html">MdEditor application</a></li><li><a href="./../addons/core.html">Core addon</a></li><li><a href="./../addons/md/">Md UI addon</a></li></ul>`,14)])])}const u=t(n,[["render",r]]);export{m as __pageData,u as default};
